mapper.select:
SELECT cv.id, cv.user_id, cv.answer_id, cv.vote_type, cv.created_at, ui.`name` AS userName, ui.images AS userImages, pq.title, pq.content AS questionContent, pa.content FROM content_votes cv LEFT JOIN user_info ui ON (ui.id = cv.user_id) LEFT JOIN party_answers pa ON (pa.id = cv.answer_id) LEFT JOIN party_questions pq ON (pq.id = pa.question_id) WHERE 1 = 1
AND ui.`name` LIKE CONCAT('%',#{queryFrom.userName},'%')
AND pq.title LIKE CONCAT('%',#{queryFrom.title},'%')
AND cv.vote_type = #{queryFrom.voteType}
AND ui.user_id = #{queryFrom.userId}
ORDER BY cv.created_at DESC
